import React, { useState } from "react";
import API from "../services/api";
import toast from "react-hot-toast";
import Card from "../components/Card";
import Button from "../components/Button";

export default function Add() {
  const [form, setForm] = useState({
    title: "",
    amount: "",
    category: "Dining",
    type: "expense",
    date: new Date().toISOString().split('T')[0],
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await API.post("/transactions", form);
      toast.success("Transaction Added 🚀"); 
      setForm({ title: "", amount: "", category: "Dining", type: "expense", date: new Date().toISOString().split('T')[0] });
    } catch (err) {
      toast.error("Something went wrong ❌"); 
    }
  };

  return (
    <div className="max-w-md mx-auto pt-8 px-4">
      <Card className="p-8">
        <h2 className="text-2xl font-bold text-gray-900 mb-6">Add Transaction</h2>

        <form onSubmit={handleSubmit} className="space-y-6">

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 block">
              What did you spend on?
            </label>
            <input
              type="text"
              name="title"
              value={form.title}
              onChange={handleChange}
              placeholder="e.g. Food, Rent"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 block">
              Amount
            </label>
            <input
              type="number"
              name="amount"
              value={form.amount}
              onChange={handleChange}
              placeholder="₹ Enter amount"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all"
              required
              step="0.01"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 block">
              Category
            </label>
            <select
              name="category"
              value={form.category}
              onChange={handleChange}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all"
            >
              <option>Dining</option>
              <option>Travel</option>
              <option>Shopping</option>
              <option>Rent</option>
              <option>Utilities</option>
              <option>Groceries</option>
              <option>Health</option>
              <option>Entertainment</option>
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 block">
              Date
            </label>
            <input
              type="date"
              name="date"
              value={form.date}
              onChange={handleChange}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 block">
              Type
            </label>
            <select
              name="type"
              value={form.type}
              onChange={handleChange}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all"
            >
              <option value="expense">Expense</option>
              <option value="income">Income</option>
            </select>
          </div>

          <Button type="submit" size="lg" className="w-full">
            Add Transaction
          </Button>

        </form>
      </Card>
    </div>
  );
}

