import { useEffect, useState } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid
} from 'recharts';
import {
  ClipboardCheck,
  CreditCard,
  DollarSign,
  FileText,
  MapPin,
  Receipt,
  Sparkles
} from 'lucide-react';
import Card from '../components/Card';
import Button from '../components/Button';
import Table from '../components/Table';

const quickActions = [
  { label: 'New Expense', icon: CreditCard },
  { label: 'Add Receipt', icon: Receipt },
  { label: 'Create Report', icon: FileText },
  { label: 'Create Trip', icon: MapPin }
];

const taskCards = [
  { label: 'Approvals', count: 7, icon: ClipboardCheck, accent: 'bg-cyan-500/15 text-cyan-300' },
  { label: 'Report drafts', count: 3, icon: FileText, accent: 'bg-violet-500/15 text-violet-300' },
  { label: 'Receipts to upload', count: 12, icon: Receipt, accent: 'bg-emerald-500/15 text-emerald-300' },
  { label: 'Active trips', count: 2, icon: MapPin, accent: 'bg-orange-500/15 text-orange-300' }
];

const teamPalette = {
  Operations: 'bg-cyan-500/10 text-cyan-300',
  Finance: 'bg-violet-500/10 text-violet-300',
  Design: 'bg-emerald-500/10 text-emerald-300',
  Sales: 'bg-sky-500/10 text-sky-300'
};

const teamNames = ['Operations', 'Finance', 'Design', 'Sales'];

export default function Dashboard() {
  const [userName, setUserName] = useState('Ana');
  const [transactions, setTransactions] = useState([]);
  const [trendData, setTrendData] = useState([]);
  const [dailyData, setDailyData] = useState([]);

  useEffect(() => {
    const userString = localStorage.getItem('user');
    const rawTx = JSON.parse(localStorage.getItem('transactions')) || [];
    const parsedUser = userString ? JSON.parse(userString) : {};

    setUserName(parsedUser.name?.split(' ')[0] || 'Ana');
    setTransactions(rawTx);
    buildCharts(rawTx);
  }, []);

  function buildCharts(txData) {
    const teamTotals = {};
    const dailyTotals = {};

    txData.forEach((tx) => {
      const date = new Date(tx.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      const team = teamNames[tx.category?.length % teamNames.length] || 'Operations';
      const amount = Math.abs(tx.amount);

      teamTotals[team] = (teamTotals[team] || 0) + amount;
      dailyTotals[date] = (dailyTotals[date] || 0) + amount;
    });

    setTrendData(
      Object.entries(teamTotals).map(([name, value]) => ({ name, amount: Number(value.toFixed(0)) }))
    );

    setDailyData(
      Object.entries(dailyTotals)
        .slice(-7)
        .map(([name, amount]) => ({ name, amount: Number(amount.toFixed(0)) }))
    );
  };

  const recentExpenses = transactions.slice(0, 6).map((tx) => {
    const team = teamNames[tx.category?.length % teamNames.length] || 'Operations';
    return {
      id: tx.id,
      subject: tx.name || 'Expense item',
      employee: userName,
      team,
      amount: `₹${Math.abs(tx.amount).toFixed(2)}`
    };
  });

  const tableColumns = [
    { header: 'Subject', accessor: 'subject' },
    { header: 'Employee', accessor: 'employee' },
    {
      header: 'Team',
      render: (row) => (
        <span className={`inline-flex rounded-full px-3 py-1 text-xs font-semibold ${teamPalette[row.team] || 'bg-slate-700 text-slate-200'}`}>
          {row.team}
        </span>
      )
    },
    { header: 'Amount', accessor: 'amount' }
  ];

  return (
    <div className="space-y-8">
      <section className="overflow-hidden rounded-[2rem] border border-slate-800 bg-slate-900/90 p-8 shadow-xl shadow-slate-950/30 backdrop-blur-sm">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-center xl:justify-between">
          <div className="max-w-2xl">
            <p className="text-xs uppercase tracking-[0.32em] text-cyan-300/80">Expense dashboard</p>
            <h1 className="mt-4 text-4xl font-semibold text-white sm:text-5xl">Welcome back, {userName}.</h1>
            <p className="mt-4 max-w-xl text-sm leading-7 text-slate-400">
              Manage approvals, track receipts, and review spending trends from one premium workspace.
            </p>
          </div>

          <div className="grid gap-4 sm:grid-cols-3 xl:w-[420px]">
            <Card className="space-y-4 p-6 bg-slate-950/90">
              <div className="flex items-center justify-between text-slate-200">
                <span className="text-sm uppercase tracking-[0.32em] text-slate-500">Balance</span>
                <Sparkles className="h-5 w-5 text-cyan-300" />
              </div>
              <p className="text-3xl font-semibold text-white">₹{transactions.reduce((sum, tx) => sum + tx.amount, 0).toFixed(2)}</p>
              <p className="text-sm text-slate-400">Across all categories this month.</p>
            </Card>

            <Card className="space-y-4 p-6 bg-slate-950/90">
              <div className="flex items-center justify-between text-slate-200">
                <span className="text-sm uppercase tracking-[0.32em] text-slate-500">Income</span>
                <DollarSign className="h-5 w-5 text-emerald-300" />
              </div>
              <p className="text-3xl font-semibold text-white">₹{transactions.filter((tx) => tx.type === 'income').reduce((sum, tx) => sum + tx.amount, 0).toFixed(2)}</p>
              <p className="text-sm text-slate-400">Revenue recorded this period.</p>
            </Card>

            <Card className="space-y-4 p-6 bg-slate-950/90">
              <div className="flex items-center justify-between text-slate-200">
                <span className="text-sm uppercase tracking-[0.32em] text-slate-500">Expenses</span>
                <CreditCard className="h-5 w-5 text-rose-400" />
              </div>
              <p className="text-3xl font-semibold text-white">₹{transactions.filter((tx) => tx.type === 'expense').reduce((sum, tx) => sum + Math.abs(tx.amount), 0).toFixed(2)}</p>
              <p className="text-sm text-slate-400">Spent across your recent trips and approvals.</p>
            </Card>
          </div>
        </div>
      </section>

      <div className="grid gap-6 xl:grid-cols-[0.95fr_1.05fr]">
        <Card className="p-6">
          <div className="mb-6 flex items-center justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.32em] text-cyan-300/80">Pending tasks</p>
              <h2 className="mt-2 text-2xl font-semibold text-white">Action items</h2>
            </div>
            <span className="inline-flex rounded-full bg-slate-800 px-4 py-2 text-sm font-semibold text-slate-200">{transactions.length} entries</span>
          </div>

          <div className="grid gap-4 sm:grid-cols-2">
            {taskCards.map((task) => {
              const Icon = task.icon;
              return (
                <div key={task.label} className="rounded-[1.75rem] border border-slate-800 bg-slate-950/90 p-5 shadow-sm transition duration-200 hover:-translate-y-0.5 hover:bg-slate-900">
                  <div className="flex items-center justify-between gap-4">
                    <div className={`inline-flex h-11 w-11 items-center justify-center rounded-2xl ${task.accent}`}>
                      <Icon className="h-5 w-5" />
                    </div>
                    <span className="text-3xl font-semibold text-white">{task.count}</span>
                  </div>
                  <p className="mt-5 text-sm text-slate-400">{task.label}</p>
                </div>
              );
            })}
          </div>
        </Card>

        <Card className="p-6">
          <div className="mb-6 flex items-center justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.32em] text-cyan-300/80">Recent expenses</p>
              <h2 className="mt-2 text-2xl font-semibold text-white">Latest activity</h2>
            </div>
            <Button variant="ghost" className="px-4 py-2 text-slate-300 ring-1 ring-slate-700 hover:bg-slate-800">
              View all
            </Button>
          </div>

          {recentExpenses.length === 0 ? (
            <div className="rounded-[1.75rem] border border-dashed border-slate-700 bg-slate-950/70 p-12 text-center text-slate-500">
              No recent expenses yet.
            </div>
          ) : (
            <Table columns={tableColumns} data={recentExpenses} />
          )}
        </Card>
      </div>

      <section className="grid gap-4 md:grid-cols-2">
        <div className="grid gap-4 sm:grid-cols-2">
          {quickActions.map((action) => {
            const Icon = action.icon;
            return (
              <button
                key={action.label}
                type="button"
                className="group rounded-[1.75rem] border border-slate-800 bg-slate-950/90 p-6 text-left transition duration-200 hover:-translate-y-0.5 hover:bg-slate-900"
              >
                <div className="inline-flex h-12 w-12 items-center justify-center rounded-3xl bg-cyan-500/15 text-cyan-300 transition duration-200 group-hover:bg-cyan-500/20">
                  <Icon className="h-5 w-5" />
                </div>
                <div className="mt-5">
                  <p className="font-semibold text-white">{action.label}</p>
                  <p className="mt-1 text-sm text-slate-400">Create or upload new items fast.</p>
                </div>
              </button>
            );
          })}
        </div>
      </section>

      <div className="grid gap-6 lg:grid-cols-2">
        <Card className="p-6">
          <div className="mb-6 flex items-center justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.32em] text-cyan-300/80">Monthly report</p>
              <h2 className="mt-2 text-2xl font-semibold text-white">Team spending trend</h2>
            </div>
            <span className="rounded-full bg-slate-800 px-4 py-2 text-sm text-slate-300">Live</span>
          </div>
          <div className="h-72 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData.length ? trendData : [{ name: 'Ops', amount: 0 }, { name: 'Fin', amount: 0 }]}> 
                <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tickMargin={12} />
                <YAxis axisLine={false} tickLine={false} tickMargin={10} />
                <Tooltip contentStyle={{ backgroundColor: '#0f172a', borderRadius: 16, border: '1px solid #1e293b' }} />
                <Bar dataKey="amount" fill="#38bdf8" radius={[12, 12, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>

        <Card className="p-6">
          <div className="mb-6 flex items-center justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.32em] text-cyan-300/80">Monthly report</p>
              <h2 className="mt-2 text-2xl font-semibold text-white">Day-to-day expenses</h2>
            </div>
            <span className="rounded-full bg-slate-800 px-4 py-2 text-sm text-slate-300">7 day view</span>
          </div>
          <div className="h-72 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dailyData.length ? dailyData : [{ name: 'Mon', amount: 0 }, { name: 'Tue', amount: 0 }]}> 
                <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tickMargin={12} />
                <YAxis axisLine={false} tickLine={false} tickMargin={10} />
                <Tooltip contentStyle={{ backgroundColor: '#0f172a', borderRadius: 16, border: '1px solid #1e293b' }} />
                <Bar dataKey="amount" fill="#a855f7" radius={[12, 12, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid
} from 'recharts';
import Card from '../components/Card';

export default function Home() {
  const [userName, setUserName] = useState('User');
  const [transactions, setTransactions] = useState([]);
  const [chartData, setChartData] = useState([]);

  // 🔥 DELETE FUNCTION
  const deleteTx = (id) => {
    const updated = transactions.filter((tx) => tx.id !== id);
    setTransactions(updated);
    localStorage.setItem("transactions", JSON.stringify(updated));

    updateChart(updated); // important
  };

  // 🔥 CHART UPDATE FUNCTION
  const updateChart = (txData) => {
    const grouped = {};

    txData.forEach(tx => {
      const day = new Date(tx.date).toLocaleDateString('en-US', {
        weekday: 'short'
      });

      if (!grouped[day]) {
        grouped[day] = { name: day, income: 0, expense: 0 };
      }

      if (tx.type === 'income') {
        grouped[day].income += tx.amount;
      } else {
        grouped[day].expense += Math.abs(tx.amount);
      }
    });

    setChartData(Object.values(grouped));
  };

  useEffect(() => {
    try {
      // 👤 USER
      const userStr = localStorage.getItem('user');
      if (userStr) {
        const parsedUser = JSON.parse(userStr);
        setUserName(parsedUser.name?.split(' ')[0] || 'User');
      }

      // 💰 TRANSACTIONS
      const txData = JSON.parse(localStorage.getItem('transactions')) || [];
      setTransactions(txData);

      updateChart(txData);

    } catch (e) {
    }
  }, []);

  return (
    <div className="p-8 space-y-8">
      {/* HEADER */}
      <header className="space-y-2">
        <h1 className="text-3xl font-bold text-gray-900">Welcome back, {userName}! 👋</h1>
        <p className="text-gray-600">
          Here's what's happening with your finances today.
        </p>
      </header>

      {/* STATS */}
      <section className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="p-8 text-center">
          <div className="text-3xl font-bold text-emerald-600 mb-1">₹{transactions.reduce((acc, tx) => acc + tx.amount, 0).toFixed(2)}</div>
          <div className="text-sm font-medium text-gray-500">Total Balance</div>
        </Card>

        <Card className="p-8 text-center">
          <div className="text-3xl font-bold text-emerald-600 mb-1">₹{transactions
            .filter(tx => tx.type === 'income')
            .reduce((acc, tx) => acc + tx.amount, 0)
            .toFixed(2)}</div>
          <div className="text-sm font-medium text-gray-500">Income</div>
        </Card>

        <Card className="p-8 text-center">
          <div className="text-3xl font-bold text-red-600 mb-1">₹{transactions
            .filter(tx => tx.type === 'expense')
            .reduce((acc, tx) => acc + Math.abs(tx.amount), 0)
            .toFixed(2)}</div>
          <div className="text-sm font-medium text-gray-500">Expenses</div>
        </Card>
      </section>

      {/* MAIN GRID */}
      <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* CHART */}
        <Card className="!p-0">
          <div className="p-6 border-b border-gray-100">
            <h3 className="text-xl font-bold text-gray-900">Spending Overview</h3>
          </div>

          <div className="p-6">
            {chartData.length === 0 ? (
              <div className="h-64 flex items-center justify-center text-gray-500">
                No data 📊
              </div>
            ) : (
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tickMargin={10} />
                  <YAxis axisLine={false} tickLine={false} tickMargin={10} />
                  <Tooltip />
                  <Bar dataKey="income" fill="#10B981" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="expense" fill="#EF4444" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </Card>

        {/* TRANSACTIONS */}
        <Card className="!p-0">
          <div className="p-6 border-b border-gray-100">
            <h3 className="text-xl font-bold text-gray-900">Recent Transactions</h3>
          </div>

          <div className="p-6 divide-y divide-gray-100">
            {transactions.length === 0 ? (
              <div className="py-12 text-center text-gray-500">
                No transactions yet 🚀
              </div>
            ) : (
              transactions.slice(0, 5).map(tx => (
                <div key={tx.id} className="py-4 flex items-center justify-between group">
                  <div className="flex items-center space-x-4">
                    <div className={`p-2 rounded-xl ${tx.type === 'income' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                      <span className="material-symbols-outlined text-sm">
                        {tx.type === 'income' ? 'account_balance_wallet' : 'shopping_bag'}
                      </span>
                    </div>
                    <div>
                      <h4 className="font-medium text-gray-900">{tx.name}</h4>
                      <span className="text-sm text-gray-500">{tx.category} • {new Date(tx.date).toLocaleDateString()}</span>
                    </div>
                  </div>

                  <div className="flex items-center space-x-4">
                    <span className={`font-semibold text-lg ${tx.type === 'income' ? 'text-emerald-600' : 'text-red-600'}`}>
                      {tx.type === 'income' ? '+' : '-'}₹{Math.abs(tx.amount).toFixed(2)}
                    </span>
                    <button
                      onClick={() => deleteTx(tx.id)}
                      className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                      title="Delete transaction"
                    >
                      <span className="material-symbols-outlined text-sm">delete</span>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </Card>

      </section>
    </div>
  );
}

import React, { useEffect, useState } from 'react';

export default function Analytics() {
  const [transactions, setTransactions] = useState([]);
  const [totalSavings, setTotalSavings] = useState(0);
  const [breakdown, setBreakdown] = useState({
    essentials: 0,
    leisure: 0,
    wellness: 0,
    subscriptions: 0,
  });

  useEffect(() => {
    try {
      const txData = JSON.parse(localStorage.getItem('transactions')) || [];
      setTransactions(txData);

      const total = txData.reduce((acc, tx) => acc + tx.amount, 0);
      setTotalSavings(total);

      const temp = {
        essentials: 0,
        leisure: 0,
        wellness: 0,
        subscriptions: 0,
      };

      txData.forEach(tx => {
        const amt = Math.abs(tx.amount);

        if (tx.category === 'Groceries' || tx.category === 'Rent') {
          temp.essentials += amt;
        } else if (tx.category === 'Entertainment') {
          temp.leisure += amt;
        } else if (tx.category === 'Health') {
          temp.wellness += amt;
        } else if (tx.category === 'Subscription') {
          temp.subscriptions += amt;
        }
      });

      setBreakdown(temp);
    } catch (e) {
    }
  }, []);

  const totalExpense =
    breakdown.essentials +
    breakdown.leisure +
    breakdown.wellness +
    breakdown.subscriptions;

  return (
    <>
      {/* HEADER */}
      <section className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="md:col-span-1 bg-gradient-to-br from-primary to-primary-container p-8 rounded-xl text-white shadow-xl">
          <p className="text-sm uppercase mb-1">Total Savings</p>

          <h3 className="text-4xl font-bold mb-4">
            ₹{totalSavings.toFixed(2)}
          </h3>

          {transactions.length === 0 && (
            <p className="text-sm opacity-70">No data yet</p>
          )}
        </div>

        {/* ALERT */}
        <div className="md:col-span-2 p-8 rounded-xl border-l-4 border-yellow-400 bg-yellow-50">
          {transactions.length === 0 ? (
            <p>No insights yet. Add transactions 🚀</p>
          ) : (
            <p>Track your spending patterns here 📊</p>
          )}
        </div>
      </section>

      {/* BREAKDOWN */}
      <section className="grid grid-cols-1 lg:grid-cols-12 gap-8 mt-8">
        <div className="lg:col-span-8 bg-gray-50 rounded-xl p-8">
          <h3 className="text-xl font-bold mb-4">Spending Trend</h3>

          {transactions.length === 0 ? (
            <div className="empty-state">
              No graph data 📉
            </div>
          ) : (
            <p className="text-sm text-gray-500">
              (Graph can be added here with Recharts)
            </p>
          )}
        </div>

        {/* CATEGORY */}
        <div className="lg:col-span-4 bg-white rounded-xl p-8 shadow">
          <h3 className="text-xl font-bold mb-6">Breakdown</h3>

          {totalExpense === 0 ? (
            <div className="empty-state">
              No expense data
            </div>
          ) : (
            <div className="space-y-4">
              {Object.entries(breakdown).map(([key, value]) => {
                const percent = totalExpense
                  ? (value / totalExpense) * 100
                  : 0;

                return (
                  <div key={key}>
                    <div className="flex justify-between text-sm">
                      <span>{key}</span>
                      <span>₹{value.toFixed(2)}</span>
                    </div>

                    <div className="w-full bg-gray-200 h-2 rounded">
                      <div
                        className="bg-blue-500 h-2 rounded"
                        style={{ width: `${percent}%` }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </section>
    </>
  );
}
